import { NextRequest, NextResponse } from 'next/server';
import mongoose from 'mongoose';
import { connectToDatabase } from '@/src/lib/db';
import { requireAuth } from '@/src/lib/requestAuth';
import { FileModel } from '@/src/models/File';

export const runtime = 'nodejs';
export const dynamic = 'force-dynamic';

function isValidObjectId(id: string): boolean {
  return mongoose.Types.ObjectId.isValid(id);
}

function contentTypeForFilename(filename: string, fallback?: string | null): string {
  const lower = filename.toLowerCase();
  if (lower.endsWith('.pdf')) return 'application/pdf';
  if (lower.endsWith('.txt')) return 'text/plain; charset=utf-8';
  if (lower.endsWith('.docx')) {
    return 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
  }
  if (lower.endsWith('.doc')) return 'application/msword';
  return fallback && typeof fallback === 'string' ? fallback : 'application/octet-stream';
}

function dispositionForFilename(filename: string): 'inline' | 'attachment' {
  const lower = filename.toLowerCase();
  return lower.endsWith('.pdf') || lower.endsWith('.txt') ? 'inline' : 'attachment';
}

export async function GET(req: NextRequest, context: { params: Promise<{ id: string }> }) {
  try {
    const user = await requireAuth(req);
    const { id } = await context.params;

    if (!isValidObjectId(id)) {
      return NextResponse.json({ success: false, error: 'Invalid id' }, { status: 400 });
    }

    await connectToDatabase();

    const file = await FileModel.findById(id)
      .select({ userId: 1, fileName: 1, fileUrl: 1 })
      .lean();

    if (!file) {
      return NextResponse.json({ success: false, error: 'Not found' }, { status: 404 });
    }

    if (!file.userId || file.userId.toString() !== user.id) {
      return NextResponse.json({ success: false, error: 'Forbidden' }, { status: 403 });
    }

    const upstream = await fetch(file.fileUrl, { cache: 'no-store' });
    if (!upstream.ok || !upstream.body) {
      return NextResponse.json(
        { success: false, error: 'Failed to fetch file content' },
        { status: 502, headers: { 'Cache-Control': 'no-store' } },
      );
    }

    const contentType = contentTypeForFilename(file.fileName, upstream.headers.get('content-type'));
    const disposition = dispositionForFilename(file.fileName);

    const headers = new Headers();
    headers.set('Content-Type', contentType);
    headers.set(
      'Content-Disposition',
      `${disposition}; filename*=UTF-8''${encodeURIComponent(file.fileName)}`,
    );
    headers.set('Cache-Control', 'no-store');

    const len = upstream.headers.get('content-length');
    if (len) headers.set('Content-Length', len);

    return new NextResponse(upstream.body, { status: 200, headers });
  } catch (error) {
    if (error instanceof Error && error.message === 'UNAUTHORIZED') {
      return NextResponse.json({ success: false, error: 'Unauthorized' }, { status: 401 });
    }

    console.error('[api/files/:id/content GET] error', error);
    return NextResponse.json({ success: false, error: 'Internal server error' }, { status: 500 });
  }
}
